import json

def compute_complement():
    A = {1: 0.7, 2: 0.5, 3: 0.3}
    complement = {x: 1 - mu for x, mu in A.items()}
    print(json.dumps({"answer": {k: v for k, v in sorted(complement.items())}}))

compute_complement()

