import json

def fuzzy_union(A, B):
    union = {}
    for key in A.keys() | B.keys():
        union[key] = max(A.get(key, 0), B.get(key, 0))
    return union

A = {1: 0.3, 2: 0.5, 3: 0.7}
B = {1: 0.4, 2: 0.6, 3: 0.2}
result = fuzzy_union(A, B)
print(json.dumps({"answer": f"{result[1]}/1 + {result[2]}/2 + {result[3]}/3"}))
